#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N1, N2, N3;
        scanf("%lld %lld %lld", &N1, &N2, &N3);
        long long result = (N1 * N2 * N3 - N1 * N2 - N2 * N3 - N1 * N3 + N1 + N2 + N3 - 2) % MOD;
        if(result < 0) result += MOD;
        printf("%lld\n", result);
    }
    return 0;
}

